// // This module is designed to accept a 24-bit input signal and produce a 24-bit output signal. It has a clock input and a reset input. On the falling edge of the clock, if reset is not asserted, the controller should load the input value into an internal register. The output should always reflect the value in the internal register. If the reset is asserted, the internal register should be cleared to zero.
module adc_controller (
    input wire clk,
    input wire reset,
    input wire [23:0] adc_input,
    output reg [23:0] adc_output
);
    reg [23:0] internal_reg;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            internal_reg <= 24'b0;
        end else begin
            internal_reg <= adc_input;
        end
    end

    always @(internal_reg) begin
        adc_output <= internal_reg;
    end
endmodule
